/* Number of samples recorded in a time interval (BLE) */
static uint16_t m_samples[NUM_OF_ADS1299] = {0};
#if defined(ADS1299)
static volatile uint32_t m_drdy_last_tick[NUM_OF_ADS1299];
static volatile uint32_t m_drdy_avg_period_us[NUM_OF_ADS1299];
static volatile bool m_drdy_seen_once[NUM_OF_ADS1299];
#endif

#if defined(ADS1299)
static uint32_t app_timer_ticks_to_us(uint32_t ticks)
{
    /* APP_TIMER runs from LFCLK (usually 32768 Hz). */
    return (uint32_t)(((uint64_t)ticks * 1000000ULL + (APP_TIMER_CLOCK_FREQ / 2u)) / APP_TIMER_CLOCK_FREQ);
}

static void drdy_interval_update(uint8_t dev_idx)
{
    uint32_t now_ticks = app_timer_cnt_get();

    if (dev_idx >= NUM_OF_ADS1299)
    {
        return;
    }

    if (!m_drdy_seen_once[dev_idx])
    {
        m_drdy_seen_once[dev_idx] = true;
        m_drdy_last_tick[dev_idx] = now_ticks;
        return;
    }

    uint32_t diff_ticks = app_timer_cnt_diff_compute(now_ticks, m_drdy_last_tick[dev_idx]);
    m_drdy_last_tick[dev_idx] = now_ticks;

    uint32_t interval_us = app_timer_ticks_to_us(diff_ticks);
    if (interval_us == 0u)
    {
        return;
    }

    /* Exponential moving average with alpha = 1/8. */
    if (m_drdy_avg_period_us[dev_idx] == 0u)
    {
        m_drdy_avg_period_us[dev_idx] = interval_us;
    }
    else
    {
        m_drdy_avg_period_us[dev_idx] =
            (uint32_t)((7u * m_drdy_avg_period_us[dev_idx] + interval_us) / 8u);
    }
}
#endif

